(9,5,2,'Collect every photo and video from guests in a digital album without apps, without complications, so simple even grandma can use it.','2025-06-23 23:21:58','2025-06-23 23:21:58'),
(10,5,1,'Mblidh çdo foto dhe video nga të ftuarit në një album digjital pa aplikacione, pa komplikime, aq e thjeshtë sa edhe gjyshja mund ta përdorë.','2025-06-23 23:21:58','2025-06-23 23:21:58'),
(11,6,2,'Get Started','2025-06-23 23:21:58','2025-06-23 23:21:58'),
(12,6,1,'Filloni','2025-06-23 23:21:58','2025-06-23 23:21:58'),
